const items = $input.all();
const biens = [];

function extractSurface(text) {
  if (!text) return null;
  const match = text.match(/(\d+)\s*m[²2]/i);
  return match ? parseInt(match[1]) : null;
}

function extractPieces(text) {
  if (!text) return null;
  const match = text.match(/([1-9])\s*pi[èe]ces?|T([1-9])|F([1-9])/i);
  if (match) {
    return parseInt(match[1] || match[2] || match[3]);
  }
  return null;
}

function detectTypeBien(text) {
  if (!text) return null;
  const lower = text.toLowerCase();
  if (lower.includes('appartement') || lower.includes('appt')) return 'appartement';
  if (lower.includes('maison') || lower.includes('villa')) return 'maison';
  if (lower.includes('terrain')) return 'terrain';
  if (lower.includes('immeuble')) return 'immeuble';
  return null;
}

const response = items[0].json;
const ads = response.ads || [];

for (const ad of ads) {
  if (!ad.list_id || !ad.subject) {
    continue;
  }

  const bien = {
    lbc_id: ad.list_id.toString(),
    titre: ad.subject,
    description: ad.body || '',
    prix: parseInt(ad.price?.[0]) || 0,
    ville: ad.location?.city || 'Non spécifié',
    code_postal: ad.location?.zipcode || '',
    url_annonce: ad.url || `https://www.leboncoin.fr/ad/${ad.list_id}`,
    photos: ad.images?.urls || [],
    nom_agence: ad.owner?.name || 'NC',
    telephone_agence: ad.owner?.phone || null,
    date_publication: ad.first_publication_date ? new Date(ad.first_publication_date).toISOString() : new Date().toISOString(),
    surface: extractSurface((ad.body || '') + ' ' + ad.subject),
    nb_pieces: extractPieces(ad.subject + ' ' + (ad.body || '')),
    type_bien: detectTypeBien(ad.subject),
    date_scraping: new Date().toISOString(),
    statut_disponibilite: 'disponible'
  };

  biens.push({ json: bien });
}

console.log(`Parsed ${biens.length} biens from API v2`);
return biens;

// Parse la réponse HTTP de Supabase et filtre uniquement les NOUVEAUX biens à enrichir
const items = $input.all();
const result = [];
let skipped = 0;

for (const item of items) {
  // La réponse Supabase peut être dans item.json (array) ou dans le body
  let bienData = null;

  if (Array.isArray(item.json)) {
    bienData = item.json[0];
  } else if (item.json && typeof item.json === 'object') {
    bienData = item.json;
  } else if (item.body) {
    const parsed = typeof item.body === 'string' ? JSON.parse(item.body) : item.body;
    bienData = Array.isArray(parsed) ? parsed[0] : parsed;
  }

  if (bienData && bienData.id) {
    // Filtrer : enrichir SEULEMENT si criteres_enrichis est NULL ou vide
    if (!bienData.criteres_enrichis || Object.keys(bienData.criteres_enrichis || {}).length === 0) {
      result.push({ json: bienData });
    } else {
      skipped++;
      console.log(`Bien ${bienData.lbc_id} déjà enrichi - skip`);
    }
  } else {
    console.error('Impossible d\'extraire les données du bien:', item);
  }
}

console.log(`Extracted ${result.length} nouveaux biens à enrichir (${skipped} déjà enrichis skippés)`);

// Si aucun bien n'a été extrait, retourner un item vide pour éviter que le workflow plante
if (result.length === 0) {
  console.warn('Aucun nouveau bien à enrichir - arrêt du workflow');
  return [{ json: { skip: true, message: 'Aucun nouveau bien à enrichir' } }];
}

return result;

// Ce nœud regroupe tous les résultats d'enrichissement
const allItems = $input.all();

const stats = {
  total_traites: allItems.length,
  enrichis_ok: allItems.filter(i => i.json.success === true).length,
  enrichis_erreur: allItems.filter(i => i.json.success !== true).length,
  score_moyen: 0
};

// Calcul du score moyen
const scoresValides = allItems
  .filter(i => i.json.success && i.json.score)
  .map(i => i.json.score);

if (scoresValides.length > 0) {
  stats.score_moyen = Math.round(
    scoresValides.reduce((sum, score) => sum + score, 0) / scoresValides.length
  );
}

console.log('Stats enrichissement:', stats);

return [{ json: stats }];
